
using LearnPath.API.Common; using LearnPath.API.DTOs.Notification; using LearnPath.API.Interfaces.Services; using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Mvc; using System.Security.Claims; namespace LearnPath.API.Controllers; [ApiController] [Route("api/v1/notifications")] [Authorize] public class NotificationController : ControllerBase { private readonly INotificationService _service; public NotificationController(INotificationService service) => _service = service; private string UserId => User.FindFirstValue(ClaimTypes.NameIdentifier)!; [HttpGet] public async Task<IActionResult> GetMy() { var result = await _service.GetMyNotificationsAsync(UserId); return Ok(ApiResponse<List<NotificationResponseDto>>.Ok(result)); } [HttpPut("{id:int}/read")] public async Task<IActionResult> MarkRead(int id) { await _service.MarkReadAsync(id, UserId); return Ok(ApiResponse<object>.Ok(null!, "Marked as read.")); } [HttpPut("read-all")] public async Task<IActionResult> MarkAllRead() { await _service.MarkAllReadAsync(UserId); return Ok(ApiResponse<object>.Ok(null!, "All marked as read.")); } }

